{
  "name": "design-os-navigator",
  "displayName": "Design Os",
  "description": "Visual node graph navigator for Design Operating System projects",
  "version": "0.7.1",
  "publisher": "MehdiVilquin",
  "repository": {
    "type": "git",
    "url": "https://github.com/MehdiVilquin/design-os-navigator"
  },
  "license": "MIT",
  "engines": {
    "vscode": "^1.85.0"
  },
  "categories": ["Other"],
  "activationEvents": [
    "workspaceContains:CLAUDE.md",
    "workspaceContains:.claude/context.md",
    "onStartupFinished"
  ],
  "main": "./out/extension.js",
  "contributes": {
    "commands": [
      {
        "command": "designOs.openNavigator",
        "title": "Design OS: Open Navigator",
        "icon": "$(compass)"
      }
    ],
    "viewsContainers": {
      "activitybar": [
        {
          "id": "design-os",
          "title": "Design OS",
          "icon": "$(compass)"
        }
      ]
    },
    "views": {
      "design-os": [
        {
          "type": "webview",
          "id": "designOsConsole",
          "name": "Console"
        }
      ]
    }
  },
  "scripts": {
    "compile": "npm run compile:ext && npm run compile:webview",
    "compile:ext": "node esbuild.config.mjs",
    "compile:webview": "vite build",
    "watch": "npm run watch:ext",
    "watch:ext": "node esbuild.config.mjs --watch",
    "watch:webview": "vite build --watch",
    "dev": "concurrently \"npm run watch:ext\" \"npm run watch:webview\"",
    "build": "npm run compile:ext -- --production && npm run compile:webview",
    "test": "vitest run",
    "test:watch": "vitest",
    "test:coverage": "vitest run --coverage",
    "lint": "eslint src --ext ts,tsx",
    "package": "npm run build && vsce package",
    "typecheck": "tsc --noEmit && tsc -p tsconfig.webview.json --noEmit"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "@types/react": "^18.2.0",
    "@types/react-dom": "^18.2.0",
    "@types/vscode": "^1.85.0",
    "@vitejs/plugin-react": "^4.2.0",
    "concurrently": "^8.2.0",
    "esbuild": "^0.20.0",
    "typescript": "^5.3.0",
    "vite": "^5.0.0",
    "vitest": "^1.2.0",
    "@vitest/coverage-v8": "^1.2.0"
  },
  "dependencies": {
    "react": "^18.2.0",
    "react-dom": "^18.2.0",
    "react-markdown": "^9.0.0",
    "remark-gfm": "^4.0.0"
  }
}

/**
 * Strategy Node Gates
 * 5 gates for the strategy phase
 */

import type { GateDefinition } from '../schema';
import { fileExists, fileHasContent, safeRead } from '../conditions/fileConditions';
import { sectionHasContent, hasValideeStatus } from '../conditions/contentConditions';

export const strategyGates: GateDefinition[] = [
  {
    id: 'strat-brief',
    label: 'Product brief rempli',
    command: '/onboarding',
    condition: (ctx) => {
      const briefPath = '01_Product/01 Strategy/product-brief.md';
      if (!fileExists(ctx, briefPath)) return false;
      return fileHasContent(ctx, briefPath, 100);
    },
  },
  {
    id: 'strat-vision',
    label: 'Vision North Star definie',
    command: '/onboarding',
    condition: (ctx) => {
      const visionPath = '01_Product/01 Strategy/northstar-vision.md';
      if (!fileExists(ctx, visionPath)) return false;
      const content = safeRead(ctx, visionPath);
      return sectionHasContent(content, '## North Star Statement', 10);
    },
  },
  {
    id: 'strat-personas',
    label: 'Personas references',
    command: '/onboarding',
    condition: (ctx) => {
      // Check if personas exist in discovery
      return ctx.personaFiles.filter(f => !f.isScaffold).length > 0;
    },
  },
  {
    id: 'strat-roadmap',
    label: 'Roadmap definie',
    command: '/onboarding',
    condition: (ctx) => {
      const roadmapPath = '01_Product/01 Strategy/roadmap.md';
      if (!fileExists(ctx, roadmapPath)) return false;
      return fileHasContent(ctx, roadmapPath, 50);
    },
  },
  {
    id: 'strat-validated',
    label: 'Brief valide (status VALIDEE)',
    command: '/onboarding',
    condition: (ctx) => {
      const briefPath = '01_Product/01 Strategy/product-brief.md';
      const content = safeRead(ctx, briefPath);
      return hasValideeStatus(content);
    },
  },
];

/**
 * Discovery Node Gates
 * 5 gates for the discovery phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles, countRealFiles } from '../conditions/fileConditions';
import { noHypotheses, hasHypotheses } from '../conditions/contentConditions';

export const discoveryGates: GateDefinition[] = [
  {
    id: 'disc-domain',
    label: 'Contexte domaine documente',
    command: '/discovery',
    condition: (ctx) => {
      return hasRealFiles(ctx.domainFiles);
    },
  },
  {
    id: 'disc-personas',
    label: '1+ persona defini',
    command: '/discovery personas',
    condition: (ctx) => {
      return countRealFiles(ctx.personaFiles) >= 1;
    },
  },
  {
    id: 'disc-interviews',
    label: 'Interviews documentes',
    command: '/discovery',
    condition: (ctx) => {
      return hasRealFiles(ctx.interviewFiles);
    },
  },
  {
    id: 'disc-insights',
    label: 'Insights synthetises',
    command: '/discovery',
    condition: (ctx) => {
      return hasRealFiles(ctx.insightFiles);
    },
  },
  {
    id: 'disc-no-hypothesis',
    label: 'Hypotheses validees (0 restantes)',
    command: '/discovery hypotheses',
    condition: (ctx) => {
      const realFiles = ctx.allDiscoveryFiles.filter(f => !f.isScaffold);
      if (realFiles.length === 0) return false;
      return noHypotheses(realFiles);
    },
  },
];

/**
 * Spec Node Gates
 * 4 gates for the spec phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles, countRealFiles } from '../conditions/fileConditions';
import { sectionsFilled, avgCompleteness, hasValideeStatus } from '../conditions/contentConditions';

export const specGates: GateDefinition[] = [
  {
    id: 'spec-exists',
    label: '1+ spec existe',
    command: '/spec',
    condition: (ctx) => {
      return hasRealFiles(ctx.specFiles);
    },
  },
  {
    id: 'spec-deep',
    label: 'Spec avec 5+ sections remplies',
    command: '/spec',
    condition: (ctx) => {
      return sectionsFilled(ctx.specFiles, 5);
    },
  },
  {
    id: 'spec-validated',
    label: 'Spec validee (status VALIDEE)',
    command: '/spec',
    condition: (ctx) => {
      const realSpecs = ctx.specFiles.filter(f => !f.isScaffold);
      return realSpecs.some(f => hasValideeStatus(f.signals.status || ''));
    },
  },
  {
    id: 'spec-complete',
    label: 'Specs completes (80%+)',
    command: '/spec',
    condition: (ctx) => {
      return avgCompleteness(ctx.specFiles, 0.8);
    },
  },
];

/**
 * Build Node Gates
 * 4 gates for the build phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles, countRealFiles } from '../conditions/fileConditions';
import { hasGoVerdict } from '../conditions/contentConditions';

export const buildGates: GateDefinition[] = [
  {
    id: 'build-src',
    label: 'Code source existe',
    command: '/build',
    condition: (ctx) => {
      return hasRealFiles(ctx.srcFiles);
    },
  },
  {
    id: 'build-tests',
    label: 'Tests existent',
    command: '/build',
    condition: (ctx) => {
      return hasRealFiles(ctx.testFiles);
    },
  },
  {
    id: 'build-coverage',
    label: 'Specs couvertes par du code',
    command: '/build',
    condition: (ctx) => {
      // Check if we have at least as many src files as specs
      const specCount = countRealFiles(ctx.specFiles);
      const srcCount = countRealFiles(ctx.srcFiles);
      return specCount > 0 && srcCount >= specCount;
    },
  },
  {
    id: 'build-review-go',
    label: 'Review GO obtenu',
    command: '/review',
    condition: (ctx) => {
      // Check if any review file has GO verdict
      return ctx.reviewFiles.some(f => {
        const content = f.signals.status || '';
        return hasGoVerdict(content);
      });
    },
  },
];

/**
 * UX Node Gates
 * 4 gates for the UX design phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles } from '../conditions/fileConditions';
import { noHypotheses, avgCompleteness } from '../conditions/contentConditions';

export const uxGates: GateDefinition[] = [
  {
    id: 'ux-files',
    label: '1+ fichier UX',
    command: '/ux',
    condition: (ctx) => {
      return hasRealFiles(ctx.uxFiles);
    },
  },
  {
    id: 'ux-screen-map',
    label: 'Screen-map defini',
    command: '/ux',
    condition: (ctx) => {
      return ctx.hasScreenMap && ctx.screenMapContent.length > 100;
    },
  },
  {
    id: 'ux-hypotheses',
    label: 'Hypotheses UX validees',
    command: '/ux',
    condition: (ctx) => {
      const realFiles = ctx.uxFiles.filter(f => !f.isScaffold);
      if (realFiles.length === 0) return false;
      return noHypotheses(realFiles);
    },
  },
  {
    id: 'ux-complete',
    label: 'Documentation UX complete (80%+)',
    command: '/ux',
    condition: (ctx) => {
      return avgCompleteness(ctx.uxFiles, 0.8);
    },
  },
];

/**
 * Review Node Gates
 * 3 gates for the review phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles, countRealFiles } from '../conditions/fileConditions';
import { hasGoVerdict } from '../conditions/contentConditions';

export const reviewGates: GateDefinition[] = [
  {
    id: 'review-exists',
    label: 'Review existe',
    command: '/review',
    condition: (ctx) => {
      return hasRealFiles(ctx.reviewFiles);
    },
  },
  {
    id: 'review-complete',
    label: 'Review complete',
    command: '/review',
    condition: (ctx) => {
      const realReviews = ctx.reviewFiles.filter(f => !f.isScaffold);
      // Check if review has sufficient content
      return realReviews.some(f => f.signals.sectionsFilled >= 3);
    },
  },
  {
    id: 'review-go',
    label: 'Verdict GO',
    command: '/review',
    condition: (ctx) => {
      return ctx.reviewFiles.some(f => {
        const content = f.signals.status || '';
        return hasGoVerdict(content);
      });
    },
  },
];

/**
 * Design System Node Gates
 * 4 gates for the design system phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles, countRealFiles } from '../conditions/fileConditions';

export const designSystemGates: GateDefinition[] = [
  {
    id: 'ds-tokens',
    label: 'Tokens definis',
    command: '/onboarding',
    condition: (ctx) => {
      const hasTokens = ctx.dsContext.tokensDefined === true ||
        (ctx.dsContext.tokens as Record<string, unknown> || {}).colors !== undefined;
      return hasTokens;
    },
  },
  {
    id: 'ds-components',
    label: 'Composants documentes',
    command: '/onboarding',
    condition: (ctx) => {
      const components = ctx.dsContext.components as unknown[];
      return Array.isArray(components) && components.length > 0;
    },
  },
  {
    id: 'ds-patterns',
    label: 'Patterns definis',
    command: '/onboarding',
    condition: (ctx) => {
      const patterns = ctx.dsContext.patterns as unknown[];
      return Array.isArray(patterns) && patterns.length > 0;
    },
  },
  {
    id: 'ds-states',
    label: 'Etats UI documentes',
    command: '/onboarding',
    condition: (ctx) => {
      const states = ctx.dsContext.states as unknown[];
      return Array.isArray(states) && states.length > 0;
    },
  },
];

/**
 * Material Node Gates
 * 3 gates for the material/raw sources phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles, countRealFiles } from '../conditions/fileConditions';

export const materialGates: GateDefinition[] = [
  {
    id: 'mat-exists',
    label: 'Material existe',
    command: '/discovery',
    condition: (ctx) => {
      return hasRealFiles(ctx.materialFiles);
    },
  },
  {
    id: 'mat-processed',
    label: 'Material traite (dispatche)',
    command: '/discovery',
    condition: (ctx) => {
      // Material is processed when we have discovery files derived from it
      const hasDiscoveryContent = hasRealFiles(ctx.allDiscoveryFiles);
      return hasDiscoveryContent;
    },
  },
  {
    id: 'mat-no-new',
    label: 'Pas de nouveau material non traite',
    command: '/discovery',
    condition: (ctx) => {
      // No new unprocessed material
      return ctx.matNewCount === 0;
    },
  },
];

/**
 * Lab Node Gates
 * 2 gates for the lab/sandbox phase
 */

import type { GateDefinition } from '../schema';
import { hasRealFiles, countRealFiles } from '../conditions/fileConditions';

export const labGates: GateDefinition[] = [
  {
    id: 'lab-exists',
    label: 'Prototypes existent',
    command: '/explore',
    condition: (ctx) => {
      return hasRealFiles(ctx.labFiles);
    },
  },
  {
    id: 'lab-active',
    label: 'Experimentation active',
    command: '/explore',
    condition: (ctx) => {
      // Lab is active if we have recent lab files
      const recentThreshold = Date.now() - 7 * 24 * 60 * 60 * 1000; // 7 days
      return ctx.labFiles.some(f => f.modifiedAt > recentThreshold);
    },
  },
];

import React, { useState, useEffect, useCallback } from 'react';
import { useVSCodeMessage, postMessage } from './hooks/useVSCode';
import { FlowPanel } from './components/Navigator/FlowPanel';
import { SidePanel } from './components/Navigator/SidePanel';
import { ArtifactFeed } from './components/Prototyper/ArtifactFeed';
import { Toast } from './components/shared/Toast';
import type { GraphData, DesignOsNode } from '../types-legacy';
import type { ExtensionMessage } from '../types/messages';
import type { Artifact } from '../types/artifact';

interface AppProps {
  initialData?: unknown;
}

type Tab = 'navigator' | 'prototyper';

interface ToastState {
  message: string;
  type: 'success' | 'error' | 'warning';
  visible: boolean;
}

export default function App({ initialData }: AppProps) {
  // VS Code API is managed by useVSCode.ts (single acquireVsCodeApi call)
  // Graph data
  const [graphData, setGraphData] = useState<GraphData | null>(
    initialData as GraphData | null
  );

  // UI state
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<Tab>('prototyper');
  // detailPanelWidth removed — SidePanel uses fixed 300px

  // Artifacts
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [loadingIds, setLoadingIds] = useState<Set<string>>(new Set());

  // Toast
  const [toast, setToast] = useState<ToastState>({ message: '', type: 'success', visible: false });

  // Handle messages from extension
  const handleMessage = useCallback((message: ExtensionMessage) => {
    switch (message.type) {
      case 'graphData':
        setGraphData(message.data);
        break;

      case 'setArtifacts':
        setArtifacts(message.artifacts);
        break;

      case 'addArtifact':
        setArtifacts(prev => [...prev, message.artifact]);
        break;

      case 'updateArtifact':
        setArtifacts(prev => prev.map(a =>
          a.id === message.artifact.id ? message.artifact : a
        ));
        break;

      case 'removeArtifact':
        setArtifacts(prev => prev.filter(a => a.id !== message.id));
        break;

      case 'setLoading':
        setLoadingIds(prev => {
          const next = new Set(prev);
          if (message.loading) {
            next.add(message.id);
          } else {
            next.delete(message.id);
          }
          return next;
        });
        break;

      case 'protoToast':
        setToast({
          message: message.message,
          type: message.toastType,
          visible: true
        });
        setTimeout(() => setToast(t => ({ ...t, visible: false })), 3000);
        break;

      case 'readinessChanged':
        // Could add a visual indicator here
        break;
    }
  }, []);

  useVSCodeMessage(handleMessage);

  // Signal to extension that React is ready to receive messages
  // This must be AFTER useVSCodeMessage to ensure listener is setup
  useEffect(() => {
    postMessage({ type: 'webviewReady' });
  }, []);

  // Get selected node
  const selectedNode: DesignOsNode | null = selectedNodeId && graphData
    ? graphData.nodes.find(n => n.id === selectedNodeId) || null
    : null;

  // Actions
  const runCommand = (command: string) => {
    postMessage({ type: 'runCommand', command });
  };

  const openFile = (path: string) => {
    postMessage({ type: 'openFile', path });
  };

  const previewFile = (path: string) => {
    postMessage({ type: 'previewFile', path });
  };

  const [consoleMenuOpen, setConsoleMenuOpen] = useState(false);
  const consoleLauncherRef = React.useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    if (!consoleMenuOpen) { return; }
    const handleOutsideClick = (e: MouseEvent) => {
      if (consoleLauncherRef.current && !consoleLauncherRef.current.contains(e.target as Node)) {
        setConsoleMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleOutsideClick);
    return () => document.removeEventListener('mousedown', handleOutsideClick);
  }, [consoleMenuOpen]);

  const launchConsole = (cli: string) => {
    postMessage({ type: 'launchConsole', cli });
    setConsoleMenuOpen(false);
  };

  // Artifact actions
  const copyArtifact = (id: string) => {
    postMessage({ type: 'copyArtifact', id });
  };

  const deleteArtifact = (id: string) => {
    postMessage({ type: 'deleteArtifact', id });
  };

  const pinArtifact = (id: string) => {
    postMessage({ type: 'pinArtifact', id });
  };

  const regenerateArtifact = (id: string, mode: 'same' | 'prompt' | 'variant', prompt?: string) => {
    postMessage({ type: 'regenerateArtifact', id, mode, prompt });
  };

  return (
    <div className="app">
      {/* Header with tabs */}
      <header className="app-header">
        <div className="header-tabs">
          <button
            type="button"
            className={`header-tab ${activeTab === 'prototyper' ? 'active' : ''}`}
            onClick={() => setActiveTab('prototyper')}
          >
            Prototyper
            {artifacts.length > 0 && (
              <span className="tab-badge">{artifacts.length}</span>
            )}
          </button>
          <button
            type="button"
            className={`header-tab ${activeTab === 'navigator' ? 'active' : ''}`}
            onClick={() => setActiveTab('navigator')}
          >
            Navigator
          </button>
        </div>
        <div className="console-launcher" ref={consoleLauncherRef}>
          <button type="button" className="launch-console-btn" onClick={() => setConsoleMenuOpen(!consoleMenuOpen)}>
            <span className="icon">◆</span> Lancer la console ▾
          </button>
          {consoleMenuOpen && (
            <div className="console-dropdown">
              <button type="button" className="console-dropdown-item" onClick={() => launchConsole('claude')}>
                claude
              </button>
            </div>
          )}
        </div>
      </header>

      {/* Main content */}
      <main className="app-content">
        {activeTab === 'navigator' && graphData && (
          <>
            <FlowPanel
              data={graphData}
              selectedNodeId={selectedNodeId}
              onSelectNode={setSelectedNodeId}
            />
            <SidePanel
              node={selectedNode}
              allNodes={graphData.nodes}
              onClose={() => setSelectedNodeId(null)}
              onRunCommand={runCommand}
              onOpenFile={openFile}
              onPreviewFile={previewFile}
            />
          </>
        )}

        {activeTab === 'prototyper' && (
          <ArtifactFeed
            artifacts={artifacts}
            loadingIds={loadingIds}
            onCopy={copyArtifact}
            onDelete={deleteArtifact}
            onPin={pinArtifact}
            onRegenerate={regenerateArtifact}
          />
        )}
      </main>

      {/* Navigator bottom bars */}
      {activeTab === 'navigator' && graphData && (
        <>
          <div className="ai-bar">
            <span className="ai-dot" />
            <span>
              <strong className="ai-label">AI</strong>
              {' — '}
              {graphData.nodes.map(n => n.label).join(' → ')}
            </span>
          </div>
          <div className="readiness-footer">
            <span className="readiness-label">Readiness</span>
            <div className="readiness-track">
              <div
                className="readiness-fill"
                style={{ '--readiness-pct': `${Math.round(graphData.globalReadiness)}%` } as React.CSSProperties}
              />
            </div>
            <span className="readiness-pct">{Math.round(graphData.globalReadiness)}%</span>
            <span className="readiness-stats">
              {graphData.nodes.length} nodes · {graphData.nodes.reduce((s, n) => s + n.fileCount, 0)} fichiers
            </span>
          </div>
        </>
      )}

      {/* Toast notifications */}
      <Toast
        message={toast.message}
        type={toast.type}
        visible={toast.visible}
        onClose={() => setToast(t => ({ ...t, visible: false }))}
      />
    </div>
  );
}

import React from 'react';
import type { DesignOsNode, GateCondition } from '../../../types-legacy';
import './NodeCard.css';

// Node icons (same as legacy)
const NODE_ICONS: Record<string, string> = {
  'material': '▣',
  'strategy': '◆',
  'discovery': '◎',
  'ux': '◇',
  'design-system': '▢',
  'spec': '▶',
  'ui': '●',
  'build': '⚙',
  'review': '✓',
  'lab': '⚡',
};

interface NodeWithPosition extends DesignOsNode {
  x: number;
  y: number;
  isChild?: boolean;
  parentId?: string;
}

interface NodeCardProps {
  node: NodeWithPosition;
  selected: boolean;
  onSelect: () => void;
}

export function NodeCard({ node, selected, onSelect }: NodeCardProps) {
  const hasAction = node.recommendedAction !== undefined;
  const isChild = node.isChild === true;

  // For child nodes, use a simpler icon
  const icon = isChild ? '◦' : (NODE_ICONS[node.id] || '○');

  return (
    <div
      className={`node status-${node.status} ${selected ? 'selected' : ''} ${hasAction ? 'has-action' : ''} ${isChild ? 'child-node' : ''}`}
      style={{ left: node.x, top: node.y }}
      onClick={onSelect}
    >
      <div className="node-header">
        <span className="node-icon">{icon}</span>
        <span className="node-label">{node.label}</span>
      </div>

      <div className="node-meta">
        <span className="node-files">{node.fileCount} fichiers</span>
        <GateDots gates={node.gates} />
      </div>

      <MaturityBadge maturity={node.maturity} />
    </div>
  );
}

// Gate dots visualization
function GateDots({ gates }: { gates: GateCondition[] }) {
  if (gates.length === 0) return null;

  return (
    <div className="gate-dots">
      {gates.map(gate => (
        <span
          key={gate.id}
          className={`gate-dot ${gate.met ? 'met' : 'unmet'}`}
          title={gate.label}
        />
      ))}
    </div>
  );
}

// Maturity badge
function MaturityBadge({ maturity }: { maturity: string }) {
  return (
    <span className={`maturity-badge maturity-${maturity.toLowerCase().replace(' ', '-')}`}>
      {maturity}
    </span>
  );
}

import React, { useState } from 'react';
import Markdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import type { Artifact } from '../../../types/artifact';
import './ArtifactCard.css';

/** Scope SVG <style> selectors and force width="100%" for proper scaling */
function prepareSvg(svgContent: string, containerId: string): string {
  // 1. Scope CSS selectors to container ID
  let result = svgContent.replace(
    /<style[^>]*>([\s\S]*?)<\/style>/gi,
    (_match, cssContent: string) => {
      const scoped = cssContent.replace(
        /([^{}]+)\{/g,
        (_r: string, sel: string) => {
          const t = sel.trim();
          if (t.startsWith('@')) return `${sel}{`;
          return t.split(',').map((s: string) => `#${containerId} ${s.trim()}`).join(', ') + ' {';
        }
      );
      return `<style>${scoped}</style>`;
    }
  );
  // 2. Force SVG to fill container width (replace or add width/height)
  result = result.replace(
    /<svg([^>]*)>/i,
    (_m, attrs: string) => {
      let a = attrs.replace(/\s*width\s*=\s*["'][^"']*["']/gi, '').replace(/\s*height\s*=\s*["'][^"']*["']/gi, '');
      return `<svg${a} width="100%" height="auto">`;
    }
  );
  return result;
}

interface ArtifactCardProps {
  artifact: Artifact;
  isSelected: boolean;
  isLoading: boolean;
  onSelect: () => void;
  onCopy: () => void;
  onDelete: () => void;
  onPin: () => void;
  onRegenerate: (mode: 'same' | 'prompt' | 'variant', prompt?: string) => void;
  // Feed mode props
  mode?: 'sidebar' | 'feed';
  onOpen?: () => void;
  regenOpen?: boolean;
  onRegenToggle?: () => void;
  menuOpen?: boolean;
  onMenuToggle?: () => void;
}

export function ArtifactCard({
  artifact,
  isSelected,
  isLoading,
  onSelect,
  onCopy,
  onDelete,
  onPin,
  onRegenerate,
  mode = 'sidebar',
  onOpen,
  regenOpen,
  onRegenToggle,
  menuOpen,
  onMenuToggle,
}: ArtifactCardProps) {
  const [showActions, setShowActions] = useState(false);

  const typeIcon = {
    doc: '▤',
    svg: '◇',
    html: '▣',
  }[artifact.type];

  const phaseColor = {
    spec: 'var(--accent)',
    design: 'var(--mauve)',
    prototype: 'var(--peach)',
  }[artifact.phase];

  const formatTime = (ts: number) => {
    const date = new Date(ts);
    return date.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
  };

  const badgeClass: Record<string, string> = {
    doc: 'feed-badge-doc',
    svg: 'feed-badge-svg',
    html: 'feed-badge-html',
    server: 'feed-badge-server',
  };

  // ── FEED MODE ──
  if (mode === 'feed') {
    return (
      <article
        className={`artifact-card-feed ${isLoading ? 'loading' : ''} ${artifact.isPinned ? 'pinned' : ''}`}
      >
        {/* Loading overlay */}
        {isLoading && (
          <div className="feed-loading-overlay">
            <span className="spinner" />
            <span className="feed-loading-text">Generation...</span>
          </div>
        )}

        {/* Header */}
        <div className="feed-header">
          <div className="feed-header-left">
            {artifact.isPinned && <span className="feed-pin">📌</span>}
            <span className={`feed-badge ${badgeClass[artifact.type] || ''}`}>
              {artifact.type.toUpperCase()}
            </span>
            <span className="feed-title">{artifact.title}</span>
          </div>
          <div className="feed-actions" onClick={e => e.stopPropagation()}>
            <button className="feed-action-btn" onClick={onOpen}>
              ↗ Ouvrir
            </button>
            <button className="feed-action-btn" onClick={onCopy}>
              📋 Copier
            </button>
            <div className="feed-dropdown-wrapper" onClick={e => e.stopPropagation()}>
              <button
                className="feed-action-btn"
                onClick={(e) => { e.stopPropagation(); onRegenToggle?.(); }}
              >
                🔄 Regenerer ▾
              </button>
              {regenOpen && (
                <div className="feed-dropdown">
                  <button className="feed-dropdown-item" onClick={() => onRegenerate('same')}>
                    <span className="feed-dropdown-icon">🔄</span> Regenerer
                  </button>
                  <button className="feed-dropdown-item" onClick={() => onRegenerate('prompt')}>
                    <span className="feed-dropdown-icon">✏️</span> Avec prompt...
                  </button>
                  <button className="feed-dropdown-item" onClick={() => onRegenerate('variant')}>
                    <span className="feed-dropdown-icon">✧</span> Variante
                  </button>
                </div>
              )}
            </div>
            <div className="feed-dropdown-wrapper" onClick={e => e.stopPropagation()}>
              <button
                className="feed-menu-btn"
                onClick={(e) => { e.stopPropagation(); onMenuToggle?.(); }}
              >
                ⋯
              </button>
              {menuOpen && (
                <div className="feed-dropdown feed-dropdown-right">
                  <button className="feed-dropdown-item" onClick={onPin}>
                    <span className="feed-dropdown-icon">{artifact.isPinned ? '📍' : '📌'}</span>
                    {artifact.isPinned ? 'Desepingler' : 'Epingler'}
                  </button>
                  <div className="feed-dropdown-divider" />
                  <button className="feed-dropdown-item feed-danger" onClick={onDelete}>
                    <span className="feed-dropdown-icon">🗑</span> Supprimer
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Content — full-size rendering */}
        <div className="feed-content">
          {artifact.type === 'svg' && (() => {
            const cid = `svg-${artifact.id.replace(/[^a-zA-Z0-9-]/g, '')}`;
            return (
              <div
                id={cid}
                className="feed-render-svg"
                dangerouslySetInnerHTML={{ __html: prepareSvg(artifact.content, cid) }}
              />
            );
          })()}
          {artifact.type === 'html' && (
            <iframe
              className="feed-render-html"
              srcDoc={artifact.content}
              sandbox="allow-scripts"
              title={artifact.title}
            />
          )}
          {artifact.type === 'doc' && (
            <div className="feed-render-doc">
              <Markdown className="markdown-body" remarkPlugins={[remarkGfm]}>
                {artifact.content}
              </Markdown>
            </div>
          )}
          {!['svg', 'html', 'doc'].includes(artifact.type) && artifact.content && (
            <div className="feed-render-doc">
              <Markdown className="markdown-body" remarkPlugins={[remarkGfm]}>
                {artifact.content}
              </Markdown>
            </div>
          )}
        </div>
      </article>
    );
  }

  // ── SIDEBAR MODE (default — unchanged) ──
  return (
    <div
      className={`artifact-card ${isSelected ? 'selected' : ''} ${artifact.isPinned ? 'pinned' : ''} ${isLoading ? 'loading' : ''}`}
      onClick={onSelect}
      onMouseEnter={() => setShowActions(true)}
      onMouseLeave={() => setShowActions(false)}
    >
      {/* Pin indicator */}
      {artifact.isPinned && <span className="pin-indicator">📌</span>}

      {/* Loading overlay */}
      {isLoading && <div className="loading-overlay"><span className="spinner" /></div>}

      {/* Header */}
      <div className="artifact-header">
        <span className="artifact-type-icon" style={{ color: phaseColor }}>{typeIcon}</span>
        <span className="artifact-title">{artifact.title}</span>
      </div>

      {/* Meta */}
      <div className="artifact-meta">
        <span className="artifact-skill">{artifact.skill}</span>
        <span className="artifact-time">{formatTime(artifact.createdAt)}</span>
      </div>

      {/* Preview thumbnails */}
      {artifact.type === 'svg' && (() => {
        const cid = `thumb-${artifact.id.replace(/[^a-zA-Z0-9-]/g, '')}`;
        return (
          <div
            id={cid}
            className="artifact-preview svg-thumbnail"
            dangerouslySetInnerHTML={{ __html: prepareSvg(artifact.content, cid) }}
          />
        );
      })()}
      {artifact.type === 'html' && (
        <div className="artifact-preview html-thumbnail">
          <span className="html-badge">HTML</span>
          <span className="html-snippet">
            {artifact.content.replace(/<[^>]*>/g, '').substring(0, 80)}
          </span>
        </div>
      )}
      {artifact.type === 'doc' && (
        <div className="artifact-preview doc-thumbnail">
          <pre className="doc-preview-text">
            {artifact.content.split('\n').slice(0, 3).join('\n').substring(0, 150)}
          </pre>
        </div>
      )}

      {/* Actions */}
      {showActions && (
        <div className="artifact-actions" onClick={e => e.stopPropagation()}>
          <button className="action-btn" onClick={onCopy} title="Copier">
            📋
          </button>
          <button className="action-btn" onClick={onPin} title={artifact.isPinned ? 'Desepingler' : 'Epingler'}>
            {artifact.isPinned ? '📍' : '📌'}
          </button>
          <button className="action-btn" onClick={() => onRegenerate('same')} title="Regenerer">
            🔄
          </button>
          <button className="action-btn delete" onClick={onDelete} title="Supprimer">
            🗑
          </button>
        </div>
      )}
    </div>
  );
}

import React from 'react';
import type { DesignOsNode } from '../../../types-legacy';
import './SidePanel.css';

const NODE_ICONS: Record<string, string> = {
  material: '▣',
  strategy: '◆',
  discovery: '◎',
  'design-system': '▢',
  ux: '◇',
  lab: '⚡',
  spec: '▶',
  ui: '●',
  build: '⚙',
  review: '✓',
};

interface SidePanelProps {
  node: DesignOsNode | null;
  allNodes: DesignOsNode[];
  onClose: () => void;
  onRunCommand: (command: string) => void;
  onOpenFile: (path: string) => void;
  onPreviewFile: (path: string) => void;
}

export function SidePanel({
  node,
  allNodes,
  onClose,
  onRunCommand,
  onOpenFile,
  onPreviewFile,
}: SidePanelProps) {
  if (!node) {
    return <div className="side-panel" />;
  }

  const metGates = node.gates.filter(g => g.met).length;
  const totalGates = node.gates.length;

  // Resolve connection labels
  const dependsLabels = node.dependsOn
    .map(id => allNodes.find(n => n.id === id))
    .filter((n): n is DesignOsNode => !!n)
    .map(n => ({ id: n.id, label: `← ${n.label}` }));

  const unlocksLabels = node.unlocks
    .map(id => allNodes.find(n => n.id === id))
    .filter((n): n is DesignOsNode => !!n)
    .map(n => ({ id: n.id, label: `→ ${n.label}` }));

  const connections = [...dependsLabels, ...unlocksLabels];

  return (
    <div className="side-panel open">
      {/* Header */}
      <div className="sp-header">
        <h3 className="sp-title">
          <span className="sp-icon">{NODE_ICONS[node.id] || '○'}</span>
          {node.label}
        </h3>
        <button className="sp-close" onClick={onClose}>×</button>
      </div>

      {/* Body */}
      <div className="sp-body">
        {/* Section: Statut */}
        <div className="sp-section">
          <div className="sp-section-title">Statut</div>
          <div className="sp-stat">
            <span className="sp-stat-label">Maturite</span>
            <span className="sp-stat-value">{node.maturity}</span>
          </div>
          <div className="sp-stat">
            <span className="sp-stat-label">Fichiers</span>
            <span className="sp-stat-value">{node.fileCount}</span>
          </div>
          <div className="sp-stat">
            <span className="sp-stat-label">Gates</span>
            <span className="sp-stat-value">{metGates}/{totalGates}</span>
          </div>
        </div>

        {/* Section: Actions (priorite haute) */}
        {node.commands.length > 0 && (
          <div className="sp-section">
            <div className="sp-section-title">Actions</div>
            {node.commands.map((cmd, i) => (
              <button
                key={cmd.command}
                className={`sp-action ${i === 0 ? 'primary' : 'secondary'}`}
                onClick={() => onRunCommand(cmd.command)}
                title={cmd.description}
              >
                {cmd.label}
              </button>
            ))}
          </div>
        )}

        {/* Section: Fichiers */}
        {node.files.length > 0 && (
          <div className="sp-section">
            <div className="sp-section-title">Fichiers</div>
            {node.files.slice(0, 10).map(file => (
              <div
                key={file.path}
                className="sp-file"
                onClick={() => onOpenFile(file.path)}
                onContextMenu={(e) => { e.preventDefault(); onPreviewFile(file.path); }}
              >
                <span className="sp-file-icon">📄</span>
                <span className="sp-file-name">{file.name}</span>
                {file.status && (
                  <span className={`sp-file-badge ${file.status.toLowerCase().replace(' ', '-')}`}>
                    {file.status}
                  </span>
                )}
              </div>
            ))}
            {node.files.length > 10 && (
              <div className="sp-more">+{node.files.length - 10} fichiers</div>
            )}
          </div>
        )}

        {/* Section: Connexions */}
        {connections.length > 0 && (
          <div className="sp-section">
            <div className="sp-section-title">Connexions</div>
            {connections.map(conn => (
              <div key={conn.id} className="sp-connection">
                {conn.label}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { ArtifactCard } from './ArtifactCard';
import { PreviewPanel } from './PreviewPanel';
import type { Artifact } from '../../../types/artifact';
import './ArtifactFeed.css';

function prepareSvg(svgContent: string, containerId: string): string {
  let result = svgContent.replace(
    /<style[^>]*>([\s\S]*?)<\/style>/gi,
    (_match, cssContent: string) => {
      const scoped = cssContent.replace(
        /([^{}]+)\{/g,
        (_r: string, sel: string) => {
          const t = sel.trim();
          if (t.startsWith('@')) return `${sel}{`;
          return t.split(',').map((s: string) => `#${containerId} ${s.trim()}`).join(', ') + ' {';
        }
      );
      return `<style>${scoped}</style>`;
    }
  );
  result = result.replace(/<svg([^>]*)>/i, (_m, attrs: string) => {
    let a = attrs.replace(/\s*width\s*=\s*["'][^"']*["']/gi, '').replace(/\s*height\s*=\s*["'][^"']*["']/gi, '');
    return `<svg${a} width="100%" height="auto">`;
  });
  return result;
}

interface ArtifactFeedProps {
  artifacts: Artifact[];
  loadingIds: Set<string>;
  onCopy: (id: string) => void;
  onDelete: (id: string) => void;
  onPin: (id: string) => void;
  onRegenerate: (id: string, mode: 'same' | 'prompt' | 'variant', prompt?: string) => void;
}

type ViewMode = 'cards' | 'realsize' | 'compact';

export function ArtifactFeed({
  artifacts,
  loadingIds,
  onCopy,
  onDelete,
  onPin,
  onRegenerate,
}: ArtifactFeedProps) {
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<ViewMode>('cards');
  const [actionMode, setActionMode] = useState<'flow' | 'variants' | 'compare'>('flow');
  const [regenOpenId, setRegenOpenId] = useState<string | null>(null);
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [previewId, setPreviewId] = useState<string | null>(null);
  const feedRef = useRef<HTMLDivElement>(null);
  const savedScrollRef = useRef<number>(0);

  // Close dropdowns on outside click
  useEffect(() => {
    const handleClick = () => {
      setRegenOpenId(null);
      setMenuOpenId(null);
    };
    document.addEventListener('click', handleClick);
    return () => document.removeEventListener('click', handleClick);
  }, []);

  // Scroll to bottom on mount (newest items are at the bottom)
  useEffect(() => {
    if (feedRef.current) {
      feedRef.current.scrollTop = feedRef.current.scrollHeight;
    }
  }, [artifacts.length]);

  // Escape key closes inline preview and restores scroll
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && previewId) {
        setPreviewId(null);
        // Restore scroll position after re-render
        requestAnimationFrame(() => {
          if (feedRef.current) {
            feedRef.current.scrollTop = savedScrollRef.current;
          }
        });
      }
    };
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [previewId]);

  // Sort: pinned first, then by createdAt asc (newest at bottom)
  const sortedArtifacts = [...artifacts].sort((a, b) => {
    if (a.isPinned !== b.isPinned) return a.isPinned ? -1 : 1;
    return a.createdAt - b.createdAt;
  });

  // Filter by type (doc, svg, html)
  const filteredByType = filterType
    ? sortedArtifacts.filter(a => a.type === filterType)
    : sortedArtifacts;

  // Filter out artifacts with empty content (they render as invisible border lines)
  const filteredArtifacts = filteredByType.filter(a => a.content?.trim().length > 0);

  // Count non-empty artifacts for the counter
  const totalNonEmpty = sortedArtifacts.filter(a => a.content?.trim().length > 0).length;

  const selectedArtifact = artifacts.find(a => a.id === selectedId);

  const formatTime = (ts: number) => {
    const date = new Date(ts);
    return date.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
  };

  const typeIcon: Record<string, string> = {
    doc: '▤',
    svg: '◇',
    html: '▣',
  };

  const phaseColor: Record<string, string> = {
    spec: 'var(--accent)',
    design: 'var(--mauve)',
    prototype: 'var(--peach)',
  };

  // Render Real Size layout — inline preview or feed using ArtifactCard mode="feed"
  const renderRealSize = () => {
    const previewArtifact = artifacts.find(a => a.id === previewId);

    // Inline preview mode
    if (previewArtifact) {
      const previewBadgeClass: Record<string, string> = {
        doc: 'rs-badge-doc', svg: 'rs-badge-svg', html: 'rs-badge-html', server: 'rs-badge-server',
      };
      return (
        <div className="rs-preview-mode">
          <div className="rs-preview-header">
            <div className="rs-preview-header-left">
              <button className="rs-back-btn" onClick={() => {
                setPreviewId(null);
                // Restore scroll position after re-render
                requestAnimationFrame(() => {
                  if (feedRef.current) {
                    feedRef.current.scrollTop = savedScrollRef.current;
                  }
                });
              }}>
                ← Retour
              </button>
              <span className={`rs-badge ${previewBadgeClass[previewArtifact.type] || ''}`}>
                {previewArtifact.type.toUpperCase()}
              </span>
              <span className="rs-preview-title">{previewArtifact.title}</span>
            </div>
            <div className="rs-preview-actions">
              <button className="rs-action-btn" onClick={() => onCopy(previewArtifact.id)}>
                📋 Copier
              </button>
            </div>
          </div>
          <div className="rs-preview-content">
            {previewArtifact.type === 'svg' && (() => {
              const cid = `rsp-${previewArtifact.id.replace(/[^a-zA-Z0-9-]/g, '')}`;
              return (
                <div
                  id={cid}
                  className="rs-preview-svg"
                  dangerouslySetInnerHTML={{ __html: prepareSvg(previewArtifact.content, cid) }}
                />
              );
            })()}
            {previewArtifact.type === 'html' && (
              <iframe
                className="rs-preview-iframe"
                srcDoc={previewArtifact.content}
                sandbox="allow-scripts"
                title={previewArtifact.title}
              />
            )}
            {previewArtifact.type === 'doc' && (
              <div className="rs-preview-doc">
                <pre>{previewArtifact.content}</pre>
              </div>
            )}
          </div>
          <div className="rs-preview-hint">Echap pour revenir au feed</div>
        </div>
      );
    }

    // Feed mode — uses ArtifactCard with mode="feed"
    const pinnedArtifacts = filteredArtifacts.filter(a => a.isPinned);
    const regularArtifacts = filteredArtifacts.filter(a => !a.isPinned);

    const renderFeedCard = (artifact: Artifact) => (
      <ArtifactCard
        key={artifact.id}
        artifact={artifact}
        isSelected={false}
        isLoading={loadingIds.has(artifact.id)}
        mode="feed"
        onSelect={() => {}}
        onOpen={() => {
          // Save scroll position before opening preview
          savedScrollRef.current = feedRef.current?.scrollTop ?? 0;
          setPreviewId(artifact.id);
        }}
        onCopy={() => onCopy(artifact.id)}
        onDelete={() => { onDelete(artifact.id); setMenuOpenId(null); }}
        onPin={() => { onPin(artifact.id); setMenuOpenId(null); }}
        onRegenerate={(mode, prompt) => { onRegenerate(artifact.id, mode, prompt); setRegenOpenId(null); }}
        regenOpen={regenOpenId === artifact.id}
        onRegenToggle={() => {
          setRegenOpenId(regenOpenId === artifact.id ? null : artifact.id);
          setMenuOpenId(null);
        }}
        menuOpen={menuOpenId === artifact.id}
        onMenuToggle={() => {
          setMenuOpenId(menuOpenId === artifact.id ? null : artifact.id);
          setRegenOpenId(null);
        }}
      />
    );

    return (
      <div className="rs-feed" ref={feedRef}>
        {filteredArtifacts.length === 0 ? (
          <div className="empty-state">
            <span className="empty-icon">◇</span>
            <p>Aucun artefact</p>
            <p className="empty-hint">Les fichiers crees par les skills apparaitront ici</p>
          </div>
        ) : (
          <>
            {pinnedArtifacts.length > 0 && (
              <div className="rs-pinned-section">
                <div className="rs-pinned-label">📌 Epingles</div>
                {pinnedArtifacts.map(renderFeedCard)}
              </div>
            )}
            {regularArtifacts.map(renderFeedCard)}
          </>
        )}
      </div>
    );
  };

  // Render Compact layout
  const renderCompact = () => (
    <div className="compact-layout">
      {filteredArtifacts.length === 0 ? (
        <div className="empty-state">
          <span className="empty-icon">◇</span>
          <p>Aucun artefact</p>
          <p className="empty-hint">Les fichiers crees par les skills apparaitront ici</p>
        </div>
      ) : (
        filteredArtifacts.map(artifact => (
          <div
            key={artifact.id}
            className={`compact-row ${selectedId === artifact.id ? 'selected' : ''}`}
            onClick={() => setSelectedId(artifact.id)}
          >
            <span
              className="compact-dot"
              style={{ background: phaseColor[artifact.phase] }}
            />
            <span className="compact-icon">{typeIcon[artifact.type]}</span>
            <span className="compact-title">{artifact.title}</span>
            {artifact.isPinned && <span className="compact-pin">📌</span>}
            <span className="compact-skill">{artifact.skill}</span>
            <span className="compact-time">{formatTime(artifact.createdAt)}</span>
          </div>
        ))
      )}
    </div>
  );

  // Render Cards layout (default)
  const renderCards = () => (
    <div className="prototyper-container">
      {/* Sidebar with artifact list */}
      <div className="artifact-sidebar">
        {/* Artifact cards */}
        <div className="artifact-list">
          {filteredArtifacts.length === 0 ? (
            <div className="empty-state">
              <span className="empty-icon">◇</span>
              <p>Aucun artefact</p>
              <p className="empty-hint">Les fichiers crees par les skills apparaitront ici</p>
            </div>
          ) : (
            filteredArtifacts.map(artifact => (
              <ArtifactCard
                key={artifact.id}
                artifact={artifact}
                isSelected={artifact.id === selectedId}
                isLoading={loadingIds.has(artifact.id)}
                onSelect={() => setSelectedId(artifact.id)}
                onCopy={() => onCopy(artifact.id)}
                onDelete={() => onDelete(artifact.id)}
                onPin={() => onPin(artifact.id)}
                onRegenerate={(mode, prompt) => onRegenerate(artifact.id, mode, prompt)}
              />
            ))
          )}
        </div>
      </div>

      {/* Preview panel */}
      <PreviewPanel
        artifact={selectedArtifact}
        onClose={() => setSelectedId(null)}
      />
    </div>
  );

  return (
    <div className="prototyper-wrapper">
      {/* Sub-header with filters, action mode, and view mode switch */}
      <div className="prototyper-subheader">
        {/* Filter by type */}
        <div className="filter-tabs">
          <button
            className={`filter-tab ${!filterType ? 'active' : ''}`}
            onClick={() => setFilterType(null)}
          >
            Tous ({totalNonEmpty})
          </button>
          <button
            className={`filter-tab ${filterType === 'doc' ? 'active' : ''}`}
            onClick={() => setFilterType('doc')}
          >
            Docs
          </button>
          <button
            className={`filter-tab ${filterType === 'svg' ? 'active' : ''}`}
            onClick={() => setFilterType('svg')}
          >
            SVG
          </button>
          <button
            className={`filter-tab ${filterType === 'html' ? 'active' : ''}`}
            onClick={() => setFilterType('html')}
          >
            HTML
          </button>
        </div>

        {/* Action mode pills */}
        <div className="action-mode-pills">
          <button
            className={`action-pill ${actionMode === 'flow' ? 'active' : ''}`}
            onClick={() => setActionMode('flow')}
          >
            Flow
          </button>
          <button
            className={`action-pill disabled`}
            disabled
            title="Bientôt disponible"
          >
            Variants
          </button>
          <button
            className={`action-pill disabled`}
            disabled
            title="Bientôt disponible"
          >
            Compare
          </button>
        </div>

        {/* View mode switch */}
        <div className="view-mode-switch">
          <button
            className={`view-mode-btn ${viewMode === 'realsize' ? 'active' : ''}`}
            onClick={() => setViewMode('realsize')}
            title="Taille réelle"
          >
            ▢
          </button>
          <button
            className={`view-mode-btn ${viewMode === 'cards' ? 'active' : ''}`}
            onClick={() => setViewMode('cards')}
            title="Cartes"
          >
            ▦
          </button>
          <button
            className={`view-mode-btn ${viewMode === 'compact' ? 'active' : ''}`}
            onClick={() => setViewMode('compact')}
            title="Compact"
          >
            ≡
          </button>
        </div>
      </div>

      {/* Content based on view mode */}
      {viewMode === 'cards' && renderCards()}
      {viewMode === 'realsize' && renderRealSize()}
      {viewMode === 'compact' && renderCompact()}
    </div>
  );
}

