import type { Artifact } from '../../../types/artifact';
import './ArtifactFeed.css';

function prepareSvg(svgContent: string, containerId: string): string {
  let result = svgContent.replace(
    /<style[^>]*>([\s\S]*?)<\/style>/gi,
