        regenOpen={regenOpenId === artifact.id}
        onRegenToggle={() => {
          setRegenOpenId(regenOpenId === artifact.id ? null : artifact.id);
          setMenuOpenId(null);
        }}
        menuOpen={menuOpenId === artifact.id}
        onMenuToggle={() => {
          setMenuOpenId(menuOpenId === artifact.id ? null : artifact.id);
          setRegenOpenId(null);
