          <div
            key={artifact.id}
            className={`compact-row ${selectedId === artifact.id ? 'selected' : ''}`}
            onClick={() => setSelectedId(artifact.id)}
          >
            <span
              className="compact-dot"
              style={{ background: phaseColor[artifact.phase] }}
            />
