            {artifact.isPinned && <span className="compact-pin">📌</span>}
            <span className="compact-skill">{artifact.skill}</span>
            <span className="compact-time">{formatTime(artifact.createdAt)}</span>
          </div>
        ))
      )}
    </div>
  );

