            Flow
          </button>
          <button
            className={`action-pill disabled`}
            disabled
            title="Bientôt disponible"
          >
            Variants
          </button>
          <button
            className={`action-pill disabled`}
            disabled
            title="Bientôt disponible"
          >
            Compare
          </button>
        </div>

        {/* View mode switch */}
