  );
  result = result.replace(/<svg([^>]*)>/i, (_m, attrs: string) => {
    let a = attrs.replace(/\s*width\s*=\s*["'][^"']*["']/gi, '').replace(/\s*height\s*=\s*["'][^"']*["']/gi, '');
